.theme-fandomdesktop-dark, .theme-fandomdesktop-light {
  --theme-body-background-color: #000000 !important;
  --theme-body-background-image: URL('https://static.wikia.nocookie.net/backrooms/images/e/e4/Level_694.1_spongebob%21%21.jpg/revision/latest?cb=20251119210154');
