  --theme-header-background-color: #204422 !important;
  --theme-text-color: #ffdddd !important;
  --theme-border-color: #d8a85c !important;
  --theme-link-color: #d8a85c !important;
  --theme-link-hover-color: #ffeebb !important;
  --theme-community-header-color: var(--theme-link-color) !important;
  --theme-sticky-nav-background-color: var(--theme-page-background-color--secondary) !important;
  --theme-sticky-nav-text-color: #ffdd99 !important;
  --theme-sticky-nav-text-color--hover: #ffeebb !important;

  --theme-selection-color: #eeffdd !important;
  --theme-selection-background-color: #204422 !important;

  --theme-body-text-opacity-factor: 0.65 !important;
  --theme-background-image-opacity: 0% !important;
}
.page__main {
  background: linear-gradient(30deg, #222044, #202244, var(--theme-header-background-color), #442220, #222044, #202244, var(--theme-header-background-color), #442220, #222044, #202244, var(--theme-header-background-color), #442220, #222044, #202244, var(--theme-header-background-color), #442220, #222044, #202244, var(--theme-header-background-color), #442220, #222044, #202244, var(--theme-header-background-color), #442220, #222044, #202244, var(--theme-header-background-color), #442220, #222044, #202244, var(--theme-header-background-color), #442220, #222044, #202244, var(--theme-header-background-color), #442220, #222044, #202244, var(--theme-header-background-color), #442220) !important;
