.page, body {
  font-family: 'Englebert' !important;
  text-shadow: 1px 0 0.1px #117711, -1px 0 0.1px #111177, 0 1px 0.1px #771111, 0 -1px 0.1px #117711 !important;
  letter-spacing: 2px;
  word-spacing: 3px;
  color: var(--theme-text-color);
}
html {
  filter: grayscale(70%);
}

.page-header, .page__title, .page-content h1, .page-content h2, .page-content h3, .page-content h4 {
  font-family: 'Chelsea Market';
  background: var(--theme-page-background-color--secondary);
  padding: 1rem;
  margin: 0.5rem 0 0.5rem 0.25rem;
  box-shadow: 0 0.2rem 0.3rem rgba(0,0,0,.25), inset 0 0 2em black, inset 0 0 0.5em white;
  border-bottom: none;
  letter-spacing: 0;
  border-radius: 30px 30px 20% 20%;
}
.page-header, .page__titls {
  padding: 3rem;
}
.lightblock {
  box-shadow: 0 0.2rem 0.3rem rgba(0, 0, 0, 0.25), inset 0 0 2em black, inset 0 0 0.5em white !important;
  border-radius: 35px;
  padding: 3rem;
  color: var(--theme-text-color);
}
.accountus-class {
  letter-spacing: 2px;
  font-weight: 200;
  color: var(--theme-link-color);
}

.sd {
  margin-top: -15px;
  display: grid;
  grid-template-columns: auto auto auto auto;
  grid-gap: 13px;
  padding: 10px;
}

.sd-box {
  position: relative;
  display: grid;
  align-items: center;
  box-shadow: 0 0.2rem 0.3rem rgba(0,0,0,0.25), inset 0 0 2em black, inset 0 0 0.5em white;
  padding: 20px;
  padding-bottom: 0px;
  font-size: 15px;
  text-align: center;
  line-height: 30px;
  background: linear-gradient(45deg, rgba(0, 0, 0, 0.1), rgba(20, 20, 20, 0.1));
  transform: scale(100%);
  transition-duration: 0.4s;
  will-change: transform;
  border-radius: 30px 30px 20% 20%;
}

.sd-box:hover {
  transform: scale(102%);
  background: linear-gradient(45deg, rgba(0, 0, 0, 0.2), rgba(20, 20, 20, 0.2));
}

.sd-main {
  grid-area: 1 / 1 / 3 / 3;
  font-size: 30px;
}

.sd-main p {
  font-size: 38px;
  margin-top: -50px;
}

.sd-sub p {
  font-size: 25px;
}

.page__main a {
  background: linear-gradient(brown,#FADB6F,brown);
  -webkit-background-clip: text !important;
  -webkit-text-fill-color: transparent;
  text-shadow: 0 0 2em #ffffff88;
  font-family: 'Chelsea Market';
  font-weight: bold;
}

.page__main a:hover {
  border-bottom: 3px groove var(--theme-border-color);
  text-decoration: none;
}
.image {
  display: inline-block;
  border: 5px groove var(--theme-border-color);
  border-radius: 10%;
  margin: 1em;
  transform: scaleX(150%) scaleY(100%);
  box-shadow: 0 0 3px black;
  transition-duration: 1s;
  will-change: transform;
  overflow: hidden;
}
.image:hover {
  transform: scaleX(160%) scaleY(110%);
  box-shadow: 0 0 5px #d8a85c;
}
.sticky-modules-wrapper{
  border-radius: 0 0 30px 30px;
  box-shadow: 0 0.2rem 0.3rem rgba(0,0,0,0.25), inset 0 0 2em black;
  padding-left: 2rem;
  background: #221033;
}
.h {
  text-shadow: 0.2px 0 0 red, 0.1px 0 0.5px red, -0.2px 0 0 blue, -0.1px 0 0.5px blue, 2px 1.8px 1px white, -3px 1.2px 1px white, 1.9px -2px 1px white, 3px -1.67px 1px white;
}
